"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

type StepperOrientation = "horizontal" | "vertical"
type StepperItemState = "active" | "completed" | "incomplete"

// ---------------------------------------------------------------------------
// StepperContext – shared by all sub-components
// ---------------------------------------------------------------------------

interface StepperContextValue {
  value: string
  onValueChange: (value: string) => void
  orientation: StepperOrientation
  /**
   * Called during render by each StepperItem to receive its ordinal position.
   * The counter is reset at the start of every Stepper render so the numbers
   * stay in sync even after re-renders.
   * @internal
   */
  getNextStepNumber: () => number
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a Stepper.")
  }
  return context
}

// ---------------------------------------------------------------------------
// StepperItemContext – scoped to each step
// ---------------------------------------------------------------------------

interface StepperItemContextValue {
  value: string
  state: StepperItemState
  stepNumber: number
  disabled: boolean
}

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a StepperItem.")
  }
  return context
}

// ---------------------------------------------------------------------------
// Stepper (root container)
// ---------------------------------------------------------------------------

interface StepperProps extends React.ComponentProps<"div"> {
  /** The currently active step value (controlled). */
  value?: string
  /** Default active step value (uncontrolled). */
  defaultValue?: string
  /** Callback fired when the active step changes. */
  onValueChange?: (value: string) => void
  /** Layout orientation of the step list. @default "horizontal" */
  orientation?: StepperOrientation
}

function Stepper({
  value: valueProp,
  defaultValue = "",
  onValueChange,
  orientation = "horizontal",
  className,
  ...props
}: StepperProps) {
  const [internalValue, setInternalValue] = React.useState(defaultValue)
  const isControlled = valueProp !== undefined
  const activeValue = isControlled ? (valueProp as string) : internalValue

  // Render-time step counter – reset before children render so each
  // StepperItem always receives the correct 1-based ordinal.
  const stepCounterRef = React.useRef(0)
  stepCounterRef.current = 0

  const getNextStepNumber = React.useCallback(
    () => ++stepCounterRef.current,
    []
  )

  const handleValueChange = React.useCallback(
    (newValue: string) => {
      if (!isControlled) setInternalValue(newValue)
      onValueChange?.(newValue)
    },
    [isControlled, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{
        value: activeValue,
        onValueChange: handleValueChange,
        orientation,
        getNextStepNumber,
      }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn("flex flex-col gap-4", className)}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperItem
// ---------------------------------------------------------------------------

interface StepperItemProps extends React.ComponentProps<"div"> {
  /** Unique identifier for this step – must match a value used in StepperContent. */
  value: string
  /** Mark this step as completed (renders a check icon in the indicator). */
  completed?: boolean
  /** Prevents the user from clicking this step. */
  disabled?: boolean
}

function StepperItem({
  value,
  completed = false,
  disabled = false,
  className,
  ...props
}: StepperItemProps) {
  const { value: activeValue, orientation, getNextStepNumber } = useStepper()
  // Capture ordinal during render – counter was reset at Stepper render start.
  const stepNumber = getNextStepNumber()

  const state: StepperItemState =
    value === activeValue ? "active" : completed ? "completed" : "incomplete"

  return (
    <StepperItemContext.Provider value={{ value, state, stepNumber, disabled }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-orientation={orientation}
        data-disabled={disabled || undefined}
        className={cn(
          "group/stepper-item flex",
          orientation === "horizontal"
            ? "flex-1 flex-row items-start last:flex-none"
            : "flex-col",
          disabled && "pointer-events-none opacity-50",
          className
        )}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperTrigger
// ---------------------------------------------------------------------------

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange, orientation } = useStepper()
  const { value, state, stepNumber, disabled } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-state={state}
      data-orientation={orientation}
      role="tab"
      aria-selected={state === "active"}
      disabled={disabled}
      onClick={() => onValueChange(value)}
      className={cn(
        "group/stepper-trigger inline-flex shrink-0 cursor-pointer rounded-md outline-none transition-colors",
        "focus-visible:ring-[3px] focus-visible:ring-ring/50",
        "disabled:pointer-events-none disabled:opacity-50",
        orientation === "horizontal"
          ? "flex-col items-center gap-2"
          : "flex-row items-center gap-3",
        className
      )}
      {...props}
    >
      {/* ── Step indicator circle ── */}
      <span
        data-slot="stepper-indicator"
        data-state={state}
        className={cn(
          "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-xs font-semibold transition-all duration-200",
          state === "active" &&
            "border-primary bg-primary text-primary-foreground",
          state === "completed" &&
            "border-primary bg-primary text-primary-foreground",
          state === "incomplete" &&
            "border-border bg-background text-muted-foreground"
        )}
      >
        {state === "completed" ? (
          <CheckIcon className="size-4" />
        ) : (
          <span aria-hidden>{stepNumber}</span>
        )}
      </span>

      {/* ── Label area (StepperTitle + StepperDescription) ── */}
      {children && (
        <span className="flex flex-col gap-0.5 text-left">{children}</span>
      )}
    </button>
  )
}

// ---------------------------------------------------------------------------
// StepperTitle
// ---------------------------------------------------------------------------

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  const { state } = useStepperItem()

  return (
    <p
      data-slot="stepper-title"
      data-state={state}
      className={cn(
        "text-sm leading-none font-medium transition-colors",
        state === "active" ? "text-foreground" : "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperDescription
// ---------------------------------------------------------------------------

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
