}

// ---------------------------------------------------------------------------
// StepperSeparator
// ---------------------------------------------------------------------------

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const { state } = useStepperItem()

  return (
    <div
      data-slot="stepper-separator"
      data-state={state}
      data-orientation={orientation}
      role="none"
      className={cn(
        "shrink-0 rounded-full bg-border transition-colors duration-200",
        // Horizontal: grow to fill the space between triggers; align with
        // the vertical centre of the size-8 (32px) indicator via mt-4 (16px).
        orientation === "horizontal" && "mx-2 mt-4 h-0.5 flex-1",
