"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const STEPS = [
  {
    value: "account",
    title: "Account",
    description: "Your login details",
  },
  {
    value: "profile",
    title: "Profile",
    description: "Personalise your account",
  },
  {
    value: "review",
    title: "Review",
    description: "Confirm &amp; submit",
  },
]

export default function StepperDemo() {
  const [currentStep, setCurrentStep] = React.useState("account")

  const currentIndex = STEPS.findIndex((s) => s.value === currentStep)
  const isFirst = currentIndex === 0
  const isLast = currentIndex === STEPS.length - 1

  function handlePrev() {
    if (!isFirst) setCurrentStep(STEPS[currentIndex - 1].value)
  }

  function handleNext() {
    if (!isLast) setCurrentStep(STEPS[currentIndex + 1].value)
  }

  return (
    <div className="w-full max-w-md space-y-6 p-4">
      <Stepper value={currentStep} onValueChange={setCurrentStep}>
        {/* ── Step list row ── */}
        <div className="flex items-start">
          {STEPS.map((step, index) => (
            <StepperItem
              key={step.value}
              value={step.value}
              completed={index < currentIndex}
            >
              <StepperTrigger>
                <StepperTitle>{step.title}</StepperTitle>
                <StepperDescription>{step.description}</StepperDescription>
              </StepperTrigger>
              {index < STEPS.length - 1 && <StepperSeparator />}
            </StepperItem>
          ))}
        </div>

        {/* ── Content panels ── */}
        <StepperContent value="account">
          <div className="rounded-lg border bg-card p-6 text-card-foreground shadow-xs">
            <h3 className="font-semibold">Account Information</h3>
            <p className="mt-1 text-sm text-muted-foreground">
              Enter your email address and create a secure password to get
              started.
            </p>
          </div>
        </StepperContent>

        <StepperContent value="profile">
          <div className="rounded-lg border bg-card p-6 text-card-foreground shadow-xs">
            <h3 className="font-semibold">Profile Details</h3>
            <p className="mt-1 text-sm text-muted-foreground">
              Tell us a bit about yourself so we can personalise your
              experience.
            </p>
          </div>
        </StepperContent>

        <StepperContent value="review">
          <div className="rounded-lg border bg-card p-6 text-card-foreground shadow-xs">
            <h3 className="font-semibold">Review &amp; Confirm</h3>
            <p className="mt-1 text-sm text-muted-foreground">
              Everything looks good? Submit when you&apos;re ready.
            </p>
          </div>
        </StepperContent>
      </Stepper>

      {/* ── Navigation ── */}
      <div className="flex justify-between">
        <Button variant="outline" disabled={isFirst} onClick={handlePrev}>
          Previous
        </Button>
        <Button onClick={handleNext}>
          {isLast ? "Submit" : "Next"}
        </Button>
      </div>
    </div>
  )
}

